const body = $json.body ?? $json;
const q = (value) => `"${String(value).replace(/"/g, '\\"')}"`;
const repoRoot = body.repoRoot || 'C:\\path\\to\\HelloWorldk';
const pythonPath = body.pythonPath || `${repoRoot}\\.venv\\Scripts\\python.exe`;
const scriptPath = body.scriptPath || `${repoRoot}\\api-batch-workflow\\openai_batch_edit.py`;
const inputDir = body.inputDir;
const outputDir = body.outputDir || `${repoRoot}\\api-batch-workflow\\output`;
const maskConfigPath = body.maskConfigPath || `${repoRoot}\\api-batch-workflow\\product_masks.json`;
const model = body.model || 'gpt-image-1';
const workers = body.workers || 2;
const apiSize = body.apiSize || '1024x1024';
const inputFidelity = body.inputFidelity || 'omit';
const saveIntermediates = body.saveIntermediates ? '--save-intermediates' : '';
const dryRun = body.dryRun ? '--dry-run' : '';
if (!inputDir) {
  throw new Error('inputDir is required');
}
if (!body.prompt) {
  throw new Error('prompt is required');
}
const command = [
  q(pythonPath),
  q(scriptPath),
  '--input-dir', q(inputDir),
  '--output-dir', q(outputDir),
  '--mask-config', q(maskConfigPath),
  '--prompt', q(body.prompt),
  '--model', q(model),
  '--workers', q(workers),
  '--api-size', q(apiSize),
  '--input-fidelity', q(inputFidelity),
  saveIntermediates,
  dryRun,
].filter(Boolean).join(' ');
return [{ json: { command, repoRoot, inputDir, outputDir, model, workers, apiSize, inputFidelity } }];
